// MARK: - UITableViewDataSource & UITableViewDelegate

extension TradingViewController: UITableViewDataSource, UITableViewDelegate {
    
    func numberOfSections(in tableView: UITableView) -> Int {
        return 1 // Main section for stocks and portfolio
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        if section == 0 {
            // Return number of stocks fetched
            return stockService.stocks.count + 1 // Add one for the header
        } else {
            // Return number of items in portfolio
            return portfolioManager.portfolioItems.count
        }
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath) as! StockTableViewCell
        
        if indexPath.section == 0 {
            // Configure stock cells
            let stock = stockService.stocks[indexPath.row - 1] // Adjust for header
            cell.configure(with: stock)
            return cell
        } else {
            // Configure portfolio cells
            let portfolioItem = portfolioManager.portfolioItems[indexPath.row]
            cell.configure(with: portfolioItem)
            return cell
        }
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        
        if indexPath.section == 0 {
            // Execute trade for selected stock
            let stock = stockService.stocks[indexPath.row - 1]
            executeTrade(for: stock)
        } else {
            // Manage or display portfolio item details
            managePortfolioItem(at: indexPath)
        }
    }
