// MARK: - Trade Execution & Portfolio Management

extension TradingViewController {
    
    private func executeTrade(for stock: Stock) {
        realTimeTradeExecution.executeTrade(stock: stock) { [weak self] success in
            if success {
                // Update portfolio and UI
                self?.portfolioManager.updatePortfolio(with: stock)
                DispatchQueue.main.async {
                    self?.tableView.reloadData()
                }
            } else {
                // Handle trade failure
                showAlert(message: "Failed to execute trade.")
            }
        }
    }
    
    private func managePortfolioItem(at indexPath: IndexPath) {
        let portfolioItem = portfolioManager.portfolioItems[indexPath.row]
        
        // Present options like sell or view details
        let actionSheet = UIAlertController(title: "Manage Portfolio Item", message: nil, preferredStyle: .actionSheet)
        
        let sellAction = UIAlertAction(title: "Sell", style: .destructive) { [weak self] _ in
            self?.sellPortfolioItem(portfolioItem)
        }
        
        let viewDetailsAction = UIAlertAction(title: "View Details", style: .default) { [weak self] _ in
            self?.viewPortfolioItemDetails(portfolioItem)
        }
        
        actionSheet.addAction(sellAction)
        actionSheet.addAction(viewDetailsAction)
        actionSheet.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        
        present(actionSheet, animated: true, completion: nil)
    }
    
    private func sellPortfolioItem(_ portfolioItem: PortfolioItem) {
        realTimeTradeExecution.sell(portfolioItem: portfolioItem) { [weak self] success in
            if success {
                // Update portfolio and UI
                self?.portfolioManager.removePortfolioItem(portfolioItem)
                DispatchQueue.main.async {
                    self?.tableView.reloadData()
                }
            } else {
                // Handle sell failure
                showAlert(message: "Failed to sell item.")
            }
        }
    }
    
    private func viewPortfolioItemDetails(_ portfolioItem: PortfolioItem) {
        let detailVC = PortfolioDetailViewController(portfolioItem: portfolioItem)
        navigationController?.pushViewController(detailVC, animated: true)
    }
}

